// Eagle only audits /resources/ anchor + cluster pages (article structure
// expected: byline, TOC, FAQ schema, contracts tagline, CTA). Excludes
// /lp/ landing pages (different content model, no byline/FAQ on purpose).
// Map the WordPress REST shape into the {fetchedUrl, slug, wpId} shape
// the downstream HTTP + Preserve Metadata + Scanner nodes expect.
const items = $input.all().map(i => i.json);
const RESOURCES = /\/resources\//;
const out = [];
for (const p of items) {
  const link = p.link || '';
  if (!RESOURCES.test(link)) continue;
  out.push({
    fetchedUrl: link,
    url: link,
    slug: p.slug || '',
    wpId: p.id || null,
    title: (p.title && p.title.rendered) || ''
  });
}
return out.map(o => ({json: o}));

const items = $input.all();
const allReports = [];
const skippedSsrEmpty = [];
const bannedRegex = /LiftNow|LIFTNOW|45\+ states|We don't subcontract|dealing directly|ALI-certified inspection|single contract line item|revolutionary|industry-leading|best-in-class|cutting-edge|In this post|in today's fast-paced|\bMohawk\b|\bStertil-Koni\b|\bRotary\b|\bSnap-on\b|\bHunter\b|\bWhip\b|\bChallenger\b|\bGray\b|\bARI\b/g;

for (const item of items) {
  const html = item.json.data || item.json.body || (typeof item.json === 'string' ? item.json : '') || '';
  const url = item.json.fetchedUrl || item.json.url || '';
  const slug = item.json.slug || '';
  const wpId = item.json.wpId || null;
  const title = item.json.title || '';

  const safeHtml = html.replace(/Challenger\s+(CLHM-?190|40\d{2}[a-z]*|44\d{2}[a-z]*)/gi, 'PRODUCT_CHALLENGER');
  const wordCount = safeHtml.replace(/<[^>]+>/g, ' ').split(/\s+/).filter(Boolean).length;

  if (wordCount < 200) {
    skippedSsrEmpty.push({url, slug, wordCount});
    continue;
  }

  const defects = [];

  // Auto-fixable structural omissions
  if (!/By Paul Stern, VP of Public Sector Sales/i.test(html))
    defects.push({type: 'MISSING_BYLINE', severity: 'high', autoFixable: true});
  if (wordCount > 1500) {
    if (!/For the Fleet Manager/i.test(html))
      defects.push({type: 'MISSING_FLEET_MANAGER_CALLOUT', severity: 'medium', autoFixable: false});
    if (!/For the Procurement Officer/i.test(html))
      defects.push({type: 'MISSING_PROCUREMENT_CALLOUT', severity: 'medium', autoFixable: false});
  }
  if (!/FAQPage/.test(html))
    defects.push({type: 'MISSING_FAQ_SCHEMA', severity: 'high', autoFixable: false});
  if (!/121223-LFT|CW7258|FSA23-EQU21\.0/.test(html))
    defects.push({type: 'MISSING_CONTRACTS_TAGLINE', severity: 'high', autoFixable: true});
  if (!/gov@liftnow\.com/i.test(html) || !/1-800-LIFT-NOW/i.test(html))
    defects.push({type: 'MISSING_CTA', severity: 'high', autoFixable: true});
  if (!/data-trust-block|wpcode-12173|Trust Block/i.test(html))
    defects.push({type: 'TRUST_BLOCK_MISSING', severity: 'high', autoFixable: false, infoOnly: true,
                  hint: 'depends on WPCode snippet #12173 — separate system, not auto-fixable via REST'});

  bannedRegex.lastIndex = 0;
  const bannedHits = [];
  let m;
  while ((m = bannedRegex.exec(safeHtml)) !== null) {
    bannedHits.push({phrase: m[0], offset: m.index});
    if (bannedHits.length >= 5) break;
  }
  if (bannedHits.length) defects.push({
    type: 'BANNED_PHRASE_DETECTED', severity: 'high', autoFixable: false,
    detail: Array.from(new Set(bannedHits.map(h => h.phrase))),
    offsets: bannedHits.map(h => h.offset)
  });

  if (defects.length) {
    const high = defects.filter(d => d.severity === 'high').length;
    allReports.push({
      url, slug, wpId, title, wordCount,
      defectCount: defects.length,
      priority: high ? 'HIGH' : 'MEDIUM',
      defects,
      currentHtml: html,
      wp_edit_url: wpId ? `https://www.liftnow.com/wp-admin/post.php?post=${wpId}&action=edit` : null
    });
  }
}

const pagesScanned = items.length;
const pagesAuditable = pagesScanned - skippedSsrEmpty.length;
const totalDefects = allReports.reduce((s,r) => s + r.defectCount, 0);

if (!allReports.length) {
  return [{json: {
    statusGreen: true,
    note: `All ${pagesAuditable} /resources/ pages passed structural checks. ${skippedSsrEmpty.length} pages skipped (SSR sparse).`,
    pages_scanned: pagesScanned
  }}];
}

// EMIT ONE ITEM PER PAGE so downstream nodes can process per-page in parallel
return allReports.map(r => ({json: r}));

// Process ALL pages — emit one item per page with patchPayload (or noAutoFix flag)
const BYLINE_HTML = "<p><em>By Paul Stern, VP of Public Sector Sales \u2014 Liftnow</em></p>\n\n";
const CTA_HTML = "\n<hr/>\n<div class=\"liftnow-cta\">\n  <h3>Ready to spec your fleet's lifts?</h3>\n  <p>Send your vehicle list and bay dimensions to <a href=\"mailto:gov@liftnow.com\">gov@liftnow.com</a>. Or call <a href=\"tel:18005438669\">1-800-LIFT-NOW</a>.</p>\n</div>\n";
const CONTRACTS_TAGLINE_HTML = "\n<p style=\"font-size:0.85em;color:#666;margin-top:2em\">\n<strong>Liftnow contracts:</strong> Sourcewell 121223-LFT \u00b7 NASPO CW7258 \u00b7 Florida Sheriffs FSA23-EQU21.0\n</p>\n";

const out = [];
for (const item of $input.all()) {
  const r = item.json;
  let patchedHtml = r.currentHtml || '';
  const autoFixesApplied = [];

  for (const d of (r.defects || [])) {
    if (!d.autoFixable) continue;
    if (d.type === 'MISSING_BYLINE') {
      const headingMatch = patchedHtml.match(/<h1[^>]*>[\s\S]*?<\/h1>/i);
      if (headingMatch) {
        const idx = headingMatch.index + headingMatch[0].length;
        patchedHtml = patchedHtml.slice(0, idx) + '\n\n' + BYLINE_HTML + patchedHtml.slice(idx);
      } else {
        patchedHtml = BYLINE_HTML + patchedHtml;
      }
      autoFixesApplied.push('MISSING_BYLINE');
    } else if (d.type === 'MISSING_CTA') {
      patchedHtml = patchedHtml + '\n\n' + CTA_HTML;
      autoFixesApplied.push('MISSING_CTA');
    } else if (d.type === 'MISSING_CONTRACTS_TAGLINE') {
      patchedHtml = patchedHtml + '\n\n' + CONTRACTS_TAGLINE_HTML;
      autoFixesApplied.push('MISSING_CONTRACTS_TAGLINE');
    }
  }

  if (!autoFixesApplied.length) {
    out.push({json: {noAutoFix: true, ...r}});
  } else {
    out.push({json: {
      ...r,
      autoFixesApplied,
      patchedHtml,
      patchPayload: { content: patchedHtml }
    }});
  }
}
return out;

// Collect results across all pages processed this run
const items = $input.all().map(i => i.json);
let autoFixedCount = 0;
let pagesAutoFixed = 0;
const remainingDefects = [];

for (const it of items) {
  if (it.autoFixesApplied && it.autoFixesApplied.length) {
    autoFixedCount += it.autoFixesApplied.length;
    pagesAutoFixed++;
  }
  // Non-auto-fixable defects are remaining
  for (const d of (it.defects || [])) {
    if (!d.autoFixable && !d.infoOnly) {
      remainingDefects.push({
        slug: it.slug || '',
        url: it.url || '',
        type: d.type,
        detail: d.detail || null,
        wp_edit_url: it.wp_edit_url || null
      });
    }
  }
}

const subject = autoFixedCount > 0
  ? "Eagle auto-fixed " + autoFixedCount + " structural defects across " + pagesAutoFixed + " pages"
  : "Eagle scan complete — " + remainingDefects.length + " content fixes need your review";

const content = "ASK\n" +
  (autoFixedCount > 0 ? "I auto-PATCHed " + autoFixedCount + " structural fixes (byline, CTA, contracts tagline) across " + pagesAutoFixed + " /resources/ pages. " : "") +
  (remainingDefects.length > 0 ? "I also found " + remainingDefects.length + " defects that need content judgment — listed below. Approve to have me draft fixes, reject to skip.\n\n" : "All structural defects are now fixed. Click Approve to log this run.\n\n") +
  (autoFixedCount > 0 ? "✅ AUTO-FIXED (already PATCHed in WP):\n" +
    items.filter(i => i.autoFixesApplied && i.autoFixesApplied.length)
      .map(i => "  • /" + (i.slug || '?') + " — " + i.autoFixesApplied.join(', '))
      .join("\n") + "\n\n" : "") +
  (remainingDefects.length > 0 ? "⚠️ NEEDS YOUR REVIEW (Eagle can't auto-fix without judgment):\n" +
    remainingDefects.map(d => "  • /" + d.slug + " — " + d.type + (d.detail ? ' (' + JSON.stringify(d.detail).slice(0,80) + ')' : ''))
      .join("\n") + "\n\n" : "") +
  "WHY\n" +
  "Eagle weekly scan of /resources/ anchor + cluster pages for structural elements: byline, FAQ schema, contracts tagline, CTA, banned phrases, Trust Block.\n\n" +
  "IF YOU APPROVE\n" +
  "I log this run in Decision Memory. If there are remaining content fixes, I'll spin up an Owl-style draft for each on the next cycle.\n\n" +
  "IF YOU REJECT\n" +
  "I'll undo the auto-PATCHes (WP keeps revisions) and revert. Tell me what to change in the comment.";

const payload = {
  properties: {
    subject: subject.slice(0, 200),
    content,
    hs_pipeline: '0',
    hs_pipeline_stage: '1',
    hs_ticket_priority: remainingDefects.length > 0 ? 'MEDIUM' : 'LOW',
    agent_name: 'UI/UX Performance',
    recommendation_type: 'Design Audit',
    recommendation_detail: JSON.stringify({
      auto_fixed_count: autoFixedCount,
      pages_auto_fixed: pagesAutoFixed,
      remaining_defects: remainingDefects,
      action_type: 'eagle_run_log'
    })
  }
};
return [{json: {body_str: JSON.stringify(payload)}}];

